import{_ as s}from"./chrome-0456080e.js";import{_ as e,a as n,b as r,c as o}from"./opera-64366fe6.js";import{_ as c,p as d,q as i,Q as t,a1 as a}from"./framework-5866ffd3.js";const l={},p=a(`<h1 id="html-img-src-属性" tabindex="-1"><a class="header-anchor" href="#html-img-src-属性" aria-hidden="true">#</a> HTML &lt;img&gt; src 属性</h1><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>图像标签如下：</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>img</span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>../assets/chrome.svg<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="定义和用法" tabindex="-1"><a class="header-anchor" href="#定义和用法" aria-hidden="true">#</a> 定义和用法</h2><p>必需的 <code>src</code> 属性指定图像的 URL。</p><p>有两种方法可以在 <code>src</code> 属性中指定 URL：</p><p><strong>① 绝对 URL</strong> - 指向托管在另一个网站上的外部图像的链接。示例：<code>src=&quot;https://jaywcjlove.github.io/html-tutorial/assets/chrome.svg&quot;</code>。</p><p><strong>注意 ⚠️：</strong> 外部图像可能受版权保护。如果您没有获得使用许可，您可能违反了版权法。此外，您无法控制外部图像；它可以突然被删除或更改。</p><p><strong>② 相对 URL</strong> - 链接到网站内托管的图像。此处，URL 不包含域名。如果 URL 开头没有斜杠，则它将相对于当前页面。示例：<code>src=&quot;chrome.svg&quot;</code>。如果 URL 以斜杠开头，它将与域相关。示例：<code>src=&quot;/assets/chrome.svg&quot;</code>。</p><p><strong>提示：</strong> 几乎总是最好使用相对 URL。如果您更改域，它们不会中断。</p><p><strong>注意 ⚠️：</strong> 如果浏览器找不到图像，则会显示断开的链接图标和 <code>alt</code> 文本。</p><h2 id="浏览器支持" tabindex="-1"><a class="header-anchor" href="#浏览器支持" aria-hidden="true">#</a> 浏览器支持</h2><table><thead><tr><th>属性 Attribute</th><th><img src="`+s+'" alt="chrome"></th><th><img src="'+e+'" alt="edge"></th><th><img src="'+n+'" alt="firefox"></th><th><img src="'+r+'" alt="safari"></th><th><img src="'+o+'" alt="opera"></th></tr></thead><tbody><tr><td>src</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td></tr></tbody></table>',14),h=a(`<h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>img</span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>URL<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="属性值" tabindex="-1"><a class="header-anchor" href="#属性值" aria-hidden="true">#</a> 属性值</h2><table><thead><tr><th>值 Value</th><th>描述 Description</th></tr></thead><tbody><tr><td><em>URL</em></td><td>图片的 URL。可能的值：<br>* 绝对 URL - 指向另一个网站（如 <code>src=&quot;http://www.example.com/image.gif&quot;</code>） <br>* 相对 URL - 指向网站内的文件（如 <code>src=&quot;image.gif&quot;</code>）</td></tr></tbody></table>`,4);function u(m,g){return d(),i("div",null,[p,t("rehype:style=width: 100%; display: inline-table;"),h,t("rehype:style=width: 100%; display: inline-table;")])}const f=c(l,[["render",u],["__file","img_src.html.vue"]]);export{f as default};
